module crystal_oscillator (  
    input wire clk,  
    input wire reset,  
    output reg out  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            out <= 0;  
        end else begin  
            out <= ~out;  
        end  
    end  
endmodule
